import { useState, useRef, useEffect } from 'react';
import { useAuth } from '../context/AuthContext';

const QUICK_PROMPTS = [
  'Best careers for PCM student in 2025?',
  'CSE vs ECE — which to choose?',
  'How to crack JEE Advanced?',
  'Government jobs after engineering?',
  'Top paying tech skills to learn?',
  'MBA vs MS after B.Tech?',
];

export default function AIChatbot() {
  const { user } = useAuth();
  const firstName = user?.name?.split(' ')[0] || 'there';
  const acad = user?.academics || {};

  const [messages, setMessages] = useState([{
    role: 'assistant',
    content: `Hi ${firstName}! 👋 I'm **Aria**, your AI Career Counselor.\n\nI can help you with:\n• Career paths & salary data (India + Global 🌍)\n• Best colleges for your profile\n• JEE / BITSAT / entrance exam strategy\n• Government exam guidance (UPSC, GATE, PSU)\n• Course & scholarship recommendations\n\nWhat would you like to explore today?`,
  }]);
  const [input, setInput] = useState('');
  const [loading, setLoading] = useState(false);
  const bottomRef = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [messages, loading]);

  const SYSTEM_PROMPT = `You are Aria, a friendly and expert AI Career Counselor for Indian students.

Student Profile:
- Name: ${user?.name || 'Student'}
- Stream: ${user?.stream || 'Science (PCM)'}
- Class 12: ${acad.p12 || 88}%
- Class 10: ${acad.p10 || 92}%
- CGPA: ${acad.cgpa || 8.4}/10
- Entrance: ${acad.entrance_exam || 'JEE Main'} — Score: ${acad.entrance_score || 145}/300
- State: ${acad.state || 'Delhi'} | Category: ${acad.category || 'General'}
- Preferred Branch: ${acad.branch || 'Computer Science (CSE)'}

Your expertise:
1. Career paths with REAL 2025 salary data — always mention both ₹ LPA (India) AND USD/yr (Global)
2. Top companies hiring for each role (Google, Microsoft, Amazon, Indian unicorns)
3. College recommendations based on JEE score
4. Exam strategy (JEE Main/Advanced, BITSAT, VITEEE, GATE, UPSC)
5. Skills & courses to learn
6. Government jobs (PSU via GATE, civil services, defense)

Rules:
- Always give BOTH Indian salary (₹ LPA) and Global salary (USD/yr)
- Be warm, encouraging, use student's first name
- Keep responses under 200 words unless asked for detail
- Use bullet points for clarity
- Give specific, actionable advice
- Mention top 3-5 companies for each career`;

  const sendMessage = async (text) => {
    const msg = text || input.trim();
    if (!msg || loading) return;
    setInput('');

    const updated = [...messages, { role: 'user', content: msg }];
    setMessages(updated);
    setLoading(true);

    // Build message history (skip first AI greeting)
    const history = updated
      .filter((m, i) => !(i === 0 && m.role === 'assistant'))
      .map(m => ({ role: m.role === 'assistant' ? 'assistant' : 'user', content: m.content }));

    // Try 1: Backend proxy
    let reply = null;
    try {
      const token = localStorage.getItem('sam_token');
      const res = await fetch('http://localhost:5000/api/chat/', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token || 'demo'}`,
        },
        body: JSON.stringify({ messages: history }),
        signal: AbortSignal.timeout(15000),
      });
      if (res.ok) {
        const data = await res.json();
        reply = data.reply;
      }
    } catch (e) {
      console.warn('Backend chat failed, trying direct API:', e.message);
    }

    // Try 2: Direct Anthropic API (works in claude.ai artifact environment)
    if (!reply) {
      try {
        const res = await fetch('https://api.anthropic.com/v1/messages', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            model: 'claude-sonnet-4-20250514',
            max_tokens: 1000,
            system: SYSTEM_PROMPT,
            messages: history,
          }),
          signal: AbortSignal.timeout(20000),
        });
        if (res.ok) {
          const data = await res.json();
          reply = data.content?.map(b => b.text || '').join('');
        }
      } catch (e) {
        console.warn('Direct API also failed:', e.message);
      }
    }

    // Fallback: Smart offline responses
    if (!reply) {
      reply = getOfflineReply(msg);
    }

    setMessages(prev => [...prev, { role: 'assistant', content: reply }]);
    setLoading(false);
  };

  const fmt = (text) => text
    .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
    .replace(/\*(.*?)\*/g, '<em>$1</em>')
    .replace(/\n/g, '<br/>');

  return (
    <div className="page-wrapper animate-in">
      <div className="page-header">
        <div className="page-header-left">
          <h1 className="page-title">🤖 AI Career Counselor</h1>
          <p className="page-subtitle">Powered by Claude AI · Career guidance with real 2025 data</p>
        </div>
        <button className="btn btn-ghost btn-sm" onClick={() => setMessages([messages[0]])}>
          Clear Chat
        </button>
      </div>

      <div className="card">
        {/* Header */}
        <div className="chat-header">
          <div className="chat-ai-avatar">🤖</div>
          <div>
            <div className="chat-ai-name">Aria — AI Counselor</div>
            <div className="chat-ai-status">Powered by Claude Sonnet</div>
          </div>
          <div style={{ marginLeft: 'auto', display: 'flex', gap: 8 }}>
            <span className="badge badge-success">● Live</span>
            <span className="badge badge-muted">{messages.length - 1} msgs</span>
          </div>
        </div>

        {/* Messages */}
        <div className="chat-messages">
          {messages.map((m, i) => (
            <div key={i} className={`chat-msg ${m.role === 'user' ? 'user' : 'ai'}`}>
              <div className={`chat-msg-avatar ${m.role === 'user' ? 'user' : 'ai'}`}>
                {m.role === 'user' ? (user?.initials || 'RS') : '🤖'}
              </div>
              <div
                className="chat-msg-bubble"
                dangerouslySetInnerHTML={{ __html: fmt(m.content) }}
              />
            </div>
          ))}
          {loading && (
            <div className="chat-msg ai">
              <div className="chat-msg-avatar ai">🤖</div>
              <div className="chat-msg-bubble">
                <div className="typing-dots"><span /><span /><span /></div>
              </div>
            </div>
          )}
          <div ref={bottomRef} />
        </div>

        {/* Quick prompts */}
        <div className="chat-quick-btns">
          {QUICK_PROMPTS.map(p => (
            <button key={p} className="chat-quick-btn" onClick={() => sendMessage(p)} disabled={loading}>
              {p}
            </button>
          ))}
        </div>

        {/* Input */}
        <div className="chat-input-row">
          <textarea
            className="chat-input"
            rows={2}
            value={input}
            placeholder="Ask about careers, colleges, exams, salaries…"
            onChange={e => setInput(e.target.value)}
            onKeyDown={e => {
              if (e.key === 'Enter' && !e.shiftKey) {
                e.preventDefault();
                sendMessage();
              }
            }}
            disabled={loading}
          />
          <button
            className="btn btn-success"
            onClick={() => sendMessage()}
            disabled={loading || !input.trim()}
          >
            {loading ? '…' : 'Send ↗'}
          </button>
        </div>
      </div>
    </div>
  );
}

